{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを正式にキックオフし、本日付で正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例は毎週水曜日10時から1時間で開催し、各部署から少なくとも1名が参加する形とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "データ移行の第1フェーズではマスタ系のみを移行し、トランザクション履歴は旧システムを参照用に残して対応する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "開発ベンダー候補は、ハギワラ技研を納期の都合で、ツヅキシステムを予算超過で見送る。",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D5",
      "content": "認証とマスタ配信の共通基盤はサクラ商事との共同利用案を採用する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "移行テストと負荷テストはシステムテストとは別立てで実施する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "新システムのユーザー権限は既存ロール定義を流用し、ロールの作り直しは稼働後の運用改善として切り分ける。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "障害発生時の一次受け窓口はQAチームとし、未知の不具合やインフラ起因の案件のみを情報システム部へエスカレーションする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "本番移行方式は、拠点をグループ分けして順番に切り替える段階移行とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D10",
      "content": "本番リリース目標日は2026-10-15に変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D11",
      "content": "切替作業は土曜深夜に実施し、日曜を予備日に充てる。",
      "decided_by": "桐生 遥"
    }
  ],
  "action_items": [
    {
      "id": "A1",
      "task": "議事録を作成して全員に共有する。",
      "assignee": "桐生 遥",
      "due": "2026-05-13"
    },
    {
      "id": "A2",
      "task": "検証環境のサーバ調達依頼を提出する。",
      "assignee": "沼田 賢一",
      "due": "2026-05-15"
    },
    {
      "id": "A3",
      "task": "ベンダー見積の社内稟議を起票する。",
      "assignee": "郡司 明久",
      "due": "2026-05-18"
    },
    {
      "id": "A4",
      "task": "現場ヒアリング対象部署のリストを想定窓口名付きで提出する。",
      "assignee": "東雲 美咲",
      "due": "2026-05-19"
    },
    {
      "id": "A5",
