      "due": "2026-05-27"
    },
    {
      "id": "A9",
      "task": "既存テストケースを棚卸しし、生きているもの・捨てるもの・要修正のものに分類した一覧を作成する。",
      "assignee": "白鳥 千夏",
      "due": "2026-05-29"
    },
    {
      "id": "A10",
      "task": "外部ライセンス費用の再見積を取得する。",
      "assignee": "郡司 明久",
      "due": "2026-06-01"
    },
    {
      "id": "A11",
      "task": "移行テスト計画を作成する。",
      "assignee": "芦田 巧",
      "due": "2026-06-03"
    },
    {
      "id": "A12",
      "task": "負荷テスト計画を作成する。",
      "assignee": "白鳥 千夏",
      "due": "2026-06-03"
    },
    {
      "id": "A13",
